example.code:
{
  "format": "executive",
  "audience": "CTO at Series-B SaaS",
  "challenger_insight": "Most teams assume incident response is a tools problem; data shows 70% of MTTR is the human handoff between detection and ownership.",
  "spin": {
    "situation": "Your on-call is 3 engineers rotating weekly.",
    "problem": "Sev-2 incidents take 40 minutes from page to active ownership.",
    "implication": "At your scale that's ~8h/month of latent customer impact + 1 escalation/month to your phone.",
    "need_payoff": "If we cut handoff latency to 5 min, you reclaim 7h/month of on-call energy and 90% of those escalations."
  },
  "cta": "Can we schedule a 30-min architecture review next Thursday?"
}
